/// {@category Providers}
library;

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/app_version_controller.dart';
import 'package:baseball_detector_flutter/controllers/locale_controller.dart';
import 'package:baseball_detector_flutter/data/repositories/api_server_repository.dart';
import 'package:baseball_detector_flutter/data/repositories/repository.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';

part 'repository_provider.g.dart';

@Riverpod(
  keepAlive: true,
  dependencies: [
    profileStorage,
    LocaleController,
    AppVersionController,
  ],
)
Repository repository(Ref ref) {
  final profileStorage = ref.watch(profileStorageProvider);
  final locale = ref.watch(localeControllerProvider);
  final appVersion = ref.watch(appVersionControllerProvider);

  return APIServerRepository(
    profileStorage: profileStorage,
    locale: locale,
    appVersion: appVersion,
  );
}

