  // pubspec.yaml の assets で登録済みのパスを Assets 経由で参照
  final jsonStr =
      await rootBundle.loadString(Assets.lib.data.models.aiCoach.sample);
  final map = json.decode(jsonStr) as Map<String, dynamic>;
  return AiCoachReport.fromJson(map);
});

